starterCode.javascript:
function calculator<T>(a: T, b: T, operator: string): T | string {
  if (operator === '+') {
    return a + b;
  } else if (operator === '-') {
    return a - b;
  } else if (operator === '*') {
    return a * b;
  } else if (operator === '/') {
    return a / b;
  } else {
    return 'Error: Invalid operator';
  }
}

