class Solution:
  def calculator(self, a: int, b: int, operator: str) -> int | str:
    if operator == '+':
      return a + b
    elif operator == '-':
      return a - b
    elif operator == '*':
      return a * b
    elif operator == '/':
      try:
        return a / b
      except ZeroDivisionError:
        return 'Error: Division by zero'
    else:
      return 'Error: Invalid operator'

